Class UserManager Extends %RegisteredObject
{
    /// Find user by username (should be case-insensitive)
    ClassMethod FindUser(username As %String) As %String
    {
        // Simulated user list
        Set users("admin") = "Administrator"
        Set users("JohnDoe") = "John Doe"
        Set users("JaneSmith") = "Jane Smith"

        // BUGGY: Direct lookup is case-sensitive
        If $DATA(users(username)) {
            Quit users(username)
        }
        Quit ""
    }
}

