Class TestUserManager Extends %RegisteredObject
{
    ClassMethod TestFindUser()
    {
        // Exact case should work
        Set result = ##class(UserManager).FindUser("admin")
        If (result '= "Administrator") {
            Throw ##class(%Exception.General).%New("FindUser('admin') failed: got "_result)
        }

        // Different case should also work
        Set result = ##class(UserManager).FindUser("ADMIN")
        If (result '= "Administrator") {
            Throw ##class(%Exception.General).%New("FindUser('ADMIN') should find admin: got "_result)
        }

        Set result = ##class(UserManager).FindUser("johndoe")
        If (result '= "John Doe") {
            Throw ##class(%Exception.General).%New("FindUser('johndoe') should find JohnDoe: got "_result)
        }
    }
}
